package main

import (
    "fmt"
    "net/http"
    "os"
    "strings"
)

// Compliant: Use configuration for IP addresses

// GOOD: Database connection from environment
func connectToDatabase() (*sql.DB, error) {
    // GOOD: Get database host from environment
    host := os.Getenv("DB_HOST")
    port := os.Getenv("DB_PORT")
    user := os.Getenv("DB_USER")
    password := os.Getenv("DB_PASSWORD")
    database := os.Getenv("DB_NAME")

    if host == "" {
        host = "localhost" // Default fallback
    }
    if port == "" {
        port = "5432" // Default PostgreSQL port
    }

    connectionString := fmt.Sprintf("postgres://%s:%s@%s:%s/%s",
        user, password, host, port, database)
    return sql.Open("postgres", connectionString)
}

// GOOD: Service discovery for external services
type ServiceConfig struct {
    BaseURL string
    Timeout time.Duration
}

func loadServiceConfig() *ServiceConfig {
    return &ServiceConfig{
        BaseURL: os.Getenv("EXTERNAL_SERVICE_URL"), // e.g., "https://api.example.com"
        Timeout: 30 * time.Second,
    }
}

func callExternalService() (*http.Response, error) {
    config := loadServiceConfig()
    if config.BaseURL == "" {
        return nil, fmt.Errorf("external service URL not configured")
    }

    client := &http.Client{Timeout: config.Timeout}
    return client.Get(config.BaseURL + "/api/users")
}

// GOOD: Service discovery for microservices
func callUserService(userID string) (*User, error) {
    serviceURL := os.Getenv("USER_SERVICE_URL")
    if serviceURL == "" {
        // Use service discovery or default
        serviceURL = discoverUserService()
    }

    url := fmt.Sprintf("%s/users/%s", serviceURL, userID)
    resp, err := http.Get(url)
    if err != nil {
        return nil, err
    }
    defer resp.Body.Close()

    // Process response
    return parseUserResponse(resp)
}

func discoverUserService() string {
    // Implement service discovery logic
    // Could use Consul, etcd, Kubernetes service discovery, etc.
    return "http://user-service:3000" // Kubernetes service name
}

// GOOD: Cache configuration from environment
func connectToRedis() (*redis.Client, error) {
    addr := os.Getenv("REDIS_ADDR")
    password := os.Getenv("REDIS_PASSWORD")

    if addr == "" {
        addr = "localhost:6379" // Default
    }

    client := redis.NewClient(&redis.Options{
        Addr:     addr,
        Password: password,
        DB:       0,
    })

    // Test connection
    _, err := client.Ping().Result()
    return client, err
}

// GOOD: Load balancer configuration
type LoadBalancerConfig struct {
    Servers []string
}

func loadServerPool() *LoadBalancerConfig {
    serversEnv := os.Getenv("BACKEND_SERVERS")
    if serversEnv == "" {
        return &LoadBalancerConfig{
            Servers: []string{"http://backend:8080"}, // Default
        }
    }

    // Parse comma-separated server list
    servers := strings.Split(serversEnv, ",")
    for i, server := range servers {
        servers[i] = strings.TrimSpace(server)
    }

    return &LoadBalancerConfig{Servers: servers}
}

// GOOD: Monitoring configuration
func sendMetrics(data []byte) error {
    metricsURL := os.Getenv("METRICS_ENDPOINT")
    if metricsURL == "" {
        // Skip metrics if not configured
        return nil
    }

    client := &http.Client{Timeout: 5 * time.Second}
    _, err := client.Post(metricsURL, "application/json", bytes.NewReader(data))
    return err
}

// GOOD: Firewall configuration from file
type NetworkConfig struct {
    AllowedIPs []string
    BlockedIPs []string
}

func loadNetworkConfig() (*NetworkConfig, error) {
    configFile := os.Getenv("NETWORK_CONFIG_FILE")
    if configFile == "" {
        configFile = "/etc/app/network.json"
    }

    data, err := ioutil.ReadFile(configFile)
    if err != nil {
        return nil, err
    }

    var config NetworkConfig
    if err := json.Unmarshal(data, &config); err != nil {
        return nil, err
    }

    return &config, nil
}

// GOOD: DNS configuration from system or environment
func getDNSServers() []string {
    dnsServers := os.Getenv("DNS_SERVERS")
    if dnsServers != "" {
        return strings.Split(dnsServers, ",")
    }

    // Use system default DNS or well-known public DNS
    return []string{
        "" + // Use system resolver
    }
}

// GOOD: Configuration structure
type AppConfig struct {
    Database    DatabaseConfig
    Services    ServicesConfig
    Cache       CacheConfig
    Monitoring  MonitoringConfig
}

type DatabaseConfig struct {
    Host     string
    Port     string
    Username string
    Password string
    Database string
}

type ServicesConfig struct {
    UserService    string
    PaymentService string
    EmailService   string
}

func loadAppConfig() (*AppConfig, error) {
    return &AppConfig{
        Database: DatabaseConfig{
            Host:     os.Getenv("DB_HOST"),
            Port:     os.Getenv("DB_PORT"),
            Username: os.Getenv("DB_USER"),
            Password: os.Getenv("DB_PASSWORD"),
            Database: os.Getenv("DB_NAME"),
        },
        Services: ServicesConfig{
            UserService:    os.Getenv("USER_SERVICE_URL"),
            PaymentService: os.Getenv("PAYMENT_SERVICE_URL"),
            EmailService:   os.Getenv("EMAIL_SERVICE_URL"),
        },
        Cache: CacheConfig{
            RedisAddr:     os.Getenv("REDIS_ADDR"),
            RedisPassword: os.Getenv("REDIS_PASSWORD"),
        },
    }, nil
}
